        const val = response.result.result ? response.result.result.value : null;
        if (val) results.push({ id: response.id, val: JSON.parse(val) });
      }
    } catch (e) {}
  });

  const expr = `
    (function() {
      var r = {};

      // 1. Check the real connection state through SDK event bus
      var imsdk = window._imsdk;
      if (imsdk) {
        var authSvc = imsdk.getAuthService();
        r.authService = {
          isLogin: authSvc ? authSvc.isLogin() : null,
          connectionStatus: authSvc ? authSvc.connectionStatus : null,
          loginUid: authSvc ? authSvc.getLoginUid() : null
        };

        // Check if there's an internal connection
        var connSvc = imsdk.getConnectionService ? imsdk.getConnectionService() : null;
        if (connSvc) {
          var connKeys = [];
          for (var k in connSvc) {
            if (typeof connSvc[k] !== 'function') connKeys.push(k + ':' + typeof connSvc[k]);
          }
          r.connectionService = { props: connKeys.slice(0, 20) };
        }
      }

      // 2. Search for ALL WebSocket instances in the page
      // WebSocket constructor might have been wrapped by the SDK
      var wsOrig = window.__originalWebSocket || WebSocket;
      r.webSocketNative = typeof wsOrig;

      // Try to find WebSocket instances registered on the page
      var wsInstances = [];
      // Check common SDK storage patterns
      var searchTargets = [
        { name: 'window._imBaaSSDK', obj: window._imBaaSSDK },
        { name: 'window._imsdk', obj: window._imsdk },
        { name: 'window.__socket__', obj: window.__socket__ },
        { name: 'window.__ws__', obj: window.__ws__ },
        { name: 'window.__connection__', obj: window.__connection__ }
      ];

      searchTargets.forEach(function(t) {
        if (!t.obj) { r[t.name] = 'undefined'; return; }
        var keys = Object.keys(t.obj).filter(function(k) {
          return typeof t.obj[k] !== 'function';
        });
        r[t.name] = { keys: keys.slice(0, 30) };

        // Deep search for WebSocket-like properties
        keys.forEach(function(k) {
          var v = t.obj[k];
          if (v && typeof v === 'object' && v.constructor) {
            var ctorName = v.constructor.name;
            if (ctorName === 'WebSocket' || ctorName.includes('Socket') || ctorName.includes('Connection')) {
              wsInstances.push({ source: t.name + '.' + k, type: ctorName, url: v.url || 'N/A', readyState: v.readyState });
            }
          }
        });
      });

