        var baaSProto = Object.getPrototypeOf(window._imBaaSSDK);
        var baaSProtoKeys = [];
        for (var k in baaSProto) baaSProtoKeys.push(k);
        r.baaSProtoKeys = baaSProtoKeys.slice(0, 40);

        // Try common internal property names
        ['_connection', '_ws', '_socket', '_transport', '_client', '_channel', 'connection', 'socket', 'ws', 'transport'].forEach(function(prop) {
          if (window._imBaaSSDK[prop]) {
            wsInstances.push({ source: '_imBaaSSDK.' + prop, type: typeof window._imBaaSSDK[prop] });
          }
        });
      }

      if (window._imsdk) {
        // Deep dive into _imsdk internals
        var imsdkAllKeys = [];
        var obj = window._imsdk;
        for (var k in obj) imsdkAllKeys.push(k);

        // Also check non-enumerable via Object.getOwnPropertyNames
        try {
          var ownKeys = Object.getOwnPropertyNames(obj);
          r.imsdkOwnKeys = ownKeys.slice(0, 50);
        } catch(e) {}

        // Search for WebSocket in nested objects
        ['_connection', '_ws', '_socket', '_transport', '_channel', '_client', '_imManager', '_chatManager'].forEach(function(prop) {
          if (obj[prop] !== undefined) {
            var v = obj[prop];
            r['imsdk.' + prop] = { type: typeof v, constructor: v && v.constructor ? v.constructor.name : 'N/A' };
            if (v && typeof v === 'object') {
              var subKeys = Object.keys(v).slice(0, 20);
              r['imsdk.' + prop + '.keys'] = subKeys;
            }
          }
        });
      }

      r.wsInstances = wsInstances;

      // 4. Try to hook WebSocket constructor to find existing instances
      // If SDK uses a wrapper, look for it
      if (window.WebSocket) {
        r.wsProto = {
          CONNECTING: WebSocket.CONNECTING,
          OPEN: WebSocket.OPEN,
          CLOSING: WebSocket.CLOSING,
          CLOSED: WebSocket.CLOSED
        };
      }

      // 5. Check if there's any global event emitter or message bus we can tap into
      r.hasMessageBus = !!window.__messageBus__;
      r.hasEventEmitter = !!window.__eventEmitter__;

      return JSON.stringify(r, null, 2);
    })()
  `;

  console.log('Deep diagnostic of SDK internals...');
  await client.send('Target.sendMessageToTarget', {
    sessionId: sessionId,
    message: JSON.stringify({
      id: 1,
      method: 'Runtime.evaluate',
      params: { expression: expr }
    })
  });

  await new Promise(r => setTimeout(r, 5000));

  if (results.length > 0) {
    console.log(results[0].val);
  } else {
    console.log('No response received');
  }

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });

