      if (imsdk) {
        var allKeys = [];
        for (var k in imsdk) allKeys.push(k);
        r.imsdkAllKeys = allKeys.slice(0, 30);

        // Try calling methods to see if they exist
        try { r.hasGetAuthService = typeof imsdk.getAuthService === 'function'; } catch(e) {}
        try { r.hasGetMessageService = typeof imsdk.getMessageService === 'function'; } catch(e) {}
        try { r.hasGetConversationService = typeof imsdk.getConversationService === 'function'; } catch(e) {}
      }

