      awaitPromise: true
    }})
  });
  await new Promise(r => setTimeout(r, 10000));
  console.log('listPrevMsgs:', JSON.stringify(results[2]));

  // Test 2: listNextMsgs
  console.log('\n=== Test 2: listNextMsgs ===');
  await client.send('Target.sendMessageToTarget', {
    sessionId,
    message: JSON.stringify({ id: 3, method: 'Runtime.evaluate', params: {
      expression: `(async function(){var imsdk=window._imsdk;var originSdk=imsdk.getOriginSdk();var paasMsgSvc=originSdk.getMsgService();try{var r=await paasMsgSvc.listNextMsgs("${cid}",20,9007199254740991);return JSON.stringify({ok:true,cnt:r?r.length:0,isArr:Array.isArray(r),type:typeof r,sample:r&&r.length>0?JSON.stringify(r[0]).substring(0,500):'empty/null'})}catch(e){return JSON.stringify({ok:false,err:e.message})}})()`,
      awaitPromise: true
    }})
  });
  await new Promise(r => setTimeout(r, 10000));
  console.log('listNextMsgs:', JSON.stringify(results[3]));

  // Test 3: Try getMessage (to see the message format)
