  await client.send('Target.sendMessageToTarget', {
    sessionId,
    message: JSON.stringify({ id: 4, method: 'Runtime.evaluate', params: {
      expression: `(async function(){var imsdk=window._imsdk;var originSdk=imsdk.getOriginSdk();var paasMsgSvc=originSdk.getMsgService();try{var r=await paasMsgSvc.getMessage("${cid}",9007199254740991);return JSON.stringify({ok:true,result:r?JSON.stringify(r).substring(0,500):'null'})}catch(e){return JSON.stringify({ok:false,err:e.message})}})()`,
      awaitPromise: true
    }})
  });
  await new Promise(r => setTimeout(r, 8000));
  console.log('getMessage:', JSON.stringify(results[4]));

  // Test 4: Try different parameter formats for listPrevMsgs
  console.log('\n=== Test 4: listPrevMsgs with different params ===');
  await client.send('Target.sendMessageToTarget', {
