  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { console.log('onettalk iframe not found'); process.exit(1); }
  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  let results = {};
  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const response = JSON.parse(msg.message);
      if (response.id && response.result) {
        const val = response.result.result ? response.result.result.value : null;
        if (val !== null && val !== undefined) {
          try { results[response.id] = JSON.parse(val); } catch(e) { results[response.id] = val; }
        }
      }
      // Log console messages for our hijack logs
      if (response.method === 'Runtime.consoleAPICalled') {
        const args = (response.params.args || []).map(a => a.value || a.description || '').join(' ');
        console.log('  [CONSOLE]', args.substring(0, 300));
      }
    } catch (e) {}
  });

  // Enable console capture
  await client.send('Target.sendMessageToTarget', {
    sessionId,
    message: JSON.stringify({ id: 0, method: 'Runtime.enable', params: {} })
  });

  // Hijack WebSocket send to capture the instance
  // Then use it to send LWP messages
  const hijackExpr = `
    (function() {
      // Store reference to the WebSocket instance
      window.__hijackedWs = null;

      // Save original send
      var originalSend = WebSocket.prototype.send;

      // Override send to capture 'this' (the WebSocket instance)
      WebSocket.prototype.send = function(data) {
        // Capture the WebSocket instance
