const BATCH_SIZE = 20;   // 每批并发数（LWP 走同一个 WS，不能太快）
const MSG_COUNT = 50;    // 每次拉取条数
const MAX_PAGES = 20;    // 单个会话最大翻页数
const BATCH_DELAY = 500;  // 批次间延迟 ms

// ========== 工具函数 ==========

function ts() { return new Date().toISOString().replace(/[:.]/g, '-'); }

function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }

// ========== 主流程 ==========

(async () => {
  log('连接 CDP...');
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  const page = pages[0];
  const client = await page.context().newCDPSession(page);

  // 找到 onetalk iframe
  const targets = await client.send('Target.getTargets');
  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
  if (!ot) { log('错误: 未找到 onetalk iframe，TM 页面是否已打开？'); process.exit(1); }
  log('onetalk iframe 已找到');

  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });

  // 响应收集
  let evalResults = {};
  let consoleMsgs = [];

  client.on('Target.receivedMessageFromTarget', (msg) => {
    if (msg.sessionId !== sessionId) return;
    try {
      const m = JSON.parse(msg.message);
      if (m.id && m.result) {
        const val = m.result.result ? m.result.result.value : null;
        if (val !== null && val !== undefined) {
          try { evalResults[m.id] = JSON.parse(val); } catch (e) { evalResults[m.id] = val; }
        } else {
          evalResults[m.id] = m.result;
        }
      }
      if (m.method === 'Runtime.consoleAPICalled') {
        const text = (m.params.args || []).map(a => a.value || a.description || '').join(' ');
        if (text.startsWith('[LWP')) consoleMsgs.push(text);
      }
    } catch (e) {}
  });

  await client.send('Target.sendMessageToTarget', {
    sessionId,
    message: JSON.stringify({ id: 0, method: 'Runtime.enable', params: {} })
  });

  // ========== Step 1: 检查并确保 SDK 已连接 ==========
  log('检查 SDK 状态...');
  await evaluate(sessionId, client, 1, `
    (function(){var a=window._imBaaSSDK.getAuthService();return JSON.stringify({isLogin:a.isLogin(),status:a.connectionStatus,uid:a.getLoginUid()})})()
  `);
  await sleep(2000);
  const sdkState = evalResults[1];
  log(`SDK: isLogin=${sdkState.isLogin}, status=${sdkState.status}, uid=${sdkState.uid}`);

  if (!sdkState.isLogin || sdkState.status < 4) {
    log('SDK 未连接，尝试 reConnect...');
    await evaluate(sessionId, client, 2, `
      (async function(){var a=window._imBaaSSDK.getAuthService();try{await a.reConnect();await new Promise(r=>setTimeout(r,3000));return JSON.stringify({isLogin:a.isLogin(),status:a.connectionStatus})}catch(e){return JSON.stringify({error:e.message})}})()
    `, true);
    await sleep(8000);
    log('reConnect 结果: ' + JSON.stringify(evalResults[2]));
  }

  // ========== Step 2: 劫持 WebSocket 并安装 LWP 收发器 ==========
  log('安装 LWP 收发器...');
  await evaluate(sessionId, client, 3, `
    (function() {
      // 保存原始 send
      var _send = WebSocket.prototype.send;
      var _ae = WebSocket.prototype.addEventListener;

      // 劫持 send 来捕获 WS 实例
      WebSocket.prototype.send = function(data) {
        if (!window.__lwpWs && this.readyState === 1) {
          window.__lwpWs = this;
          console.log('[LWP] WS captured: ' + this.url);
        }
        return _send.call(this, data);
      };

      // 劫持 addEventListener 来拦截 message 事件
      WebSocket.prototype.addEventListener = function(type, handler, options) {
        if (type === 'message') {
          var ws = this;
          var wrapped = function(event) {
            try {
              var data = typeof event.data === 'string' ? event.data : '';
              if (data.indexOf('"userMessageModels"') > -1 || data.indexOf('"code":200') > -1) {
                window.__lwpLastResponse = data;
                window.__lwpResponseTime = Date.now();
                console.log('[LWP] RESPONSE len=' + data.length);
              }
            } catch(e) {}
            return handler.call(this, event);
          };
          return _ae.call(ws, type, wrapped, options);
        }
        return _ae.call(this, type, handler, options);
      };

      // LWP 请求队列和响应处理器
      window.__lwpPending = {};   // mid -> { resolve, timeout }
      window.__lwpResponses = {}; // mid -> response data
      window.__lwpMsgId = 0;

      // 主动发 LWP 并等待响应
      window.__lwpRequest = function(lwpPath, body) {
        return new Promise(function(resolve, reject) {
          var ws = window.__lwpWs;
          if (!ws || ws.readyState !== 1) {
            reject(new Error('WS not ready'));
            return;
          }
          var mid = Date.now() + ' ' + (++window.__lwpMsgId);
          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
          window.__lwpPending[mid] = { resolve: resolve, reject: reject, time: Date.now() };
          ws.send(req);

          // 超时处理
          setTimeout(function() {
            if (window.__lwpPending[mid]) {
              delete window.__lwpPending[mid];
              reject(new Error('LWP timeout'));
            }
          }, 30000);
        });
      };

      // 检查是否有响应到达（被动轮询 __lwpLastResponse）
      window.__lwpCheckResponse = function() {
        var resp = window.__lwpLastResponse;
        if (!resp) return null;
        window.__lwpLastResponse = null;
        try {
          var parsed = JSON.parse(resp);
          var mid = parsed.headers && parsed.headers.mid;
          // 尝试匹配到 pending 请求
          if (mid && window.__lwpPending[mid]) {
            var pending = window.__lwpPending[mid];
            delete window.__lwpPending[mid];
            pending.resolve(parsed);
            return null;
          }
          // 如果匹配不到，返回原始解析结果
          return parsed;
        } catch(e) {
          return null;
        }
      };

      // 暴露用于同步请求的方法
      window.__lwpRequestSync = async function(lwpPath, body) {
        var promise = window.__lwpRequest(lwpPath, body);
        // 同时启动一个轮询来检查响应
        var checkInterval = setInterval(function() {
          var resp = window.__lwpLastResponse;
          if (resp) {
            window.__lwpLastResponse = null;
            try {
              var parsed = JSON.parse(resp);
              var mid = parsed.headers && parsed.headers.mid;
              if (mid && window.__lwpPending[mid]) {
                var pending = window.__lwpPending[mid];
                delete window.__lwpPending[mid];
                clearInterval(checkInterval);
                pending.resolve(parsed);
              }
            } catch(e) {}
          }
        }, 200);
        // 30秒超时
        setTimeout(function() { clearInterval(checkInterval); }, 30000);
        return promise;
      };

      return JSON.stringify({ installed: true, hasWs: !!window.__lwpWs });
    })()
  `);
  await sleep(3000);
  log('收发器安装: ' + JSON.stringify(evalResults[3]));

  // ========== Step 3: 如果 WS 还没捕获，等心跳触发 ==========
  await evaluate(sessionId, client, 4, `
    (function(){
      if (window.__lwpWs) return JSON.stringify({url:window.__lwpWs.url,readyState:window.__lwpWs.readyState});
      return JSON.stringify({waiting:true});
    })()
  `);
  await sleep(2000);
  if (evalResults[4] && evalResults[4].waiting) {
    log('等待 WebSocket 心跳...');
    await sleep(15000); // 等心跳触发 send
    await evaluate(sessionId, client, 5, `
      (function(){
        if (window.__lwpWs) return JSON.stringify({url:window.__lwpWs.url,readyState:window.__lwpWs.readyState});
        return JSON.stringify({failed:true});
      })()
    `);
    await sleep(2000);
    log('WS 状态: ' + JSON.stringify(evalResults[5]));
  }

  // ========== Step 4: 读取会话列表 ==========
  log('读取会话列表...');
  await evaluate(sessionId, client, 10, `
    (function(){
      var convs = window.__conversationListFullData__;
      if (!convs) return JSON.stringify({error:'no convs'});
      var list = convs.map(function(c){
        return { cid: c.cid, name: c.name, hasMsg: !!(c.latestMessage && c.latestMessage.content) };
      });
      return JSON.stringify({ total: list.length, convs: list });
    })()
  `);
  await sleep(3000);
  const convData = evalResults[10];
  log(`会话总数: ${convData.total}`);
  const allConvs = convData.convs;

  // 创建输出目录
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });

  // 检查已抓取的会话（断点续传）
  const fetched = new Set();
  if (fs.existsSync(DATA_DIR)) {
    fs.readdirSync(DATA_DIR).forEach(f => {
      if (f.endsWith('.json')) fetched.add(f.replace('.json', ''));
    });
  }
  const toFetch = allConvs.filter(c => !fetched.has(sanitizeFilename(c.cid)));
  log(`待抓取: ${toFetch.length} / 已完成: ${fetched.size}`);

  // ========== Step 5: 批量抓取 ==========
  let totalMsgs = 0;
  let errors = 0;

  for (let i = 0; i < toFetch.length; i += BATCH_SIZE) {
    const batch = toFetch.slice(i, i + BATCH_SIZE);
    log(`批次 ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(toFetch.length / BATCH_SIZE)} (${i + 1}-${Math.min(i + BATCH_SIZE, toFetch.length)})`);

    for (const conv of batch) {
      try {
        const cid = conv.cid;
        const safeName = sanitizeFilename(cid);

        // 拉取该会话的全部消息（含翻页）
        const allMessages = [];
        let cursor = 9007199254740991; // Number.MAX_SAFE_INTEGER
        let pageNum = 0;

        while (pageNum < MAX_PAGES) {
          const expr = `
            (async function() {
              try {
                var result = await window.__lwpRequestSync('/r/MessageManager/listUserMessages', ['${cid}', false, ${cursor}, ${MSG_COUNT}, false]);
                return JSON.stringify(result);
              } catch(e) {
                return JSON.stringify({ __error: e.message });
              }
            })()
          `;

          // 清除上次结果
          const msgId = 100 + i + pageNum;
          evalResults[msgId] = undefined;

          await evaluate(sessionId, client, msgId, expr, true);
          await sleep(1500); // 给 LWP 响应时间

          const raw = evalResults[msgId];
          if (!raw || raw.__error) {
            if (raw && raw.__error === 'LWP timeout') {
              log(`  [${conv.name}] 超时，跳过`);
            }
            break;
          }

          // 解析响应
          let response;
          try {
            response = typeof raw === 'string' ? JSON.parse(raw) : raw;
          } catch (e) {
            log(`  [${conv.name}] 响应解析失败`);
            break;
          }

          if (response.code !== 200) {
            log(`  [${conv.name}] code=${response.code}，停止`);
            break;
          }

          const body = response.body;
          if (!body || !body.userMessageModels || body.userMessageModels.length === 0) {
            break; // 无更多消息
          }

          const msgs = body.userMessageModels;
          allMessages.push(...msgs);

          if (msgs.length < MSG_COUNT || !body.nextCursor) {
            break; // 最后一页
          }

          cursor = body.nextCursor;
          pageNum++;
        }

        // 保存到文件
        const output = {
          cid: cid,
          name: conv.name,
          fetchedAt: new Date().toISOString(),
          totalMessages: allMessages.length,
          messages: allMessages
        };

        fs.writeFileSync(
          path.join(DATA_DIR, safeName + '.json'),
          JSON.stringify(output, null, 2)
        );

        totalMsgs += allMessages.length;
        if (allMessages.length > 0) {
          log(`  [${conv.name}] ${allMessages.length} 条消息`);
        }

      } catch (e) {
        errors++;
        if (errors < 10) log(`  [${conv.name}] 错误: ${e.message}`);
      }
    }

    log(`  批次完成，累计 ${totalMsgs} 条消息，${errors} 个错误`);
    if (i + BATCH_SIZE < toFetch.length) {
      await sleep(BATCH_DELAY);
    }
  }

  // ========== Step 6: 汇总报告 ==========
  log('');
  log('========== 抓取完成 ==========');
  log(`总会话: ${allConvs.length}`);
  log(`本次抓取: ${toFetch.length}`);
  log(`总消息数: ${totalMsgs}`);
  log(`错误数: ${errors}`);
  log(`输出目录: ${DATA_DIR}`);

  // 生成汇总
  const summary = {
    exportedAt: new Date().toISOString(),
    totalConversations: allConvs.length,
    fetchedConversations: toFetch.length,
    totalMessages: totalMsgs,
    errors: errors,
    dataDir: DATA_DIR
  };
  fs.writeFileSync(
    path.join(DATA_DIR, '_summary.json'),
    JSON.stringify(summary, null, 2)
  );

  process.exit(0);
})().catch(e => { log('致命错误: ' + e.message); process.exit(1); });

// ========== Helper ==========

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function evaluate(sessionId, client, id, expression, awaitPromise) {
  await client.send('Target.sendMessageToTarget', {
    sessionId,
    message: JSON.stringify({
      id,
      method: 'Runtime.evaluate',
      params: { expression, awaitPromise: !!awaitPromise }
    })
  });
}

function sanitizeFilename(cid) {
  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
}
