            }
            break;
          }

          // 解析响应
          let response;
          try {
            response = typeof raw === 'string' ? JSON.parse(raw) : raw;
          } catch (e) {
            log(`  [${conv.name}] 响应解析失败`);
            break;
          }

          if (response.code !== 200) {
            log(`  [${conv.name}] code=${response.code}，停止`);
            break;
          }

          const body = response.body;
          if (!body || !body.userMessageModels || body.userMessageModels.length === 0) {
            break; // 无更多消息
          }

          const msgs = body.userMessageModels;
          allMessages.push(...msgs);

          if (msgs.length < MSG_COUNT || !body.nextCursor) {
            break; // 最后一页
          }

          cursor = body.nextCursor;
          pageNum++;
        }

        // 保存到文件
