1	// OKKI CRM 全量聊天历史抓取
2	// 通过 CDP 注入 JS，劫持 WebSocket 发 LWP 协议拉取
3	// 用法: node scripts/lwp_scrape_all.js
4	// 前提: Chrome 已启动 --remote-debugging-port=9222，TM 页面已打开
5	
6	const { chromium } = require('playwright');
7	const fs = require('fs');
8	const path = require('path');
9	
10	const DATA_DIR = path.join(__dirname, '..', 'data', 'chat_history');
11	const BATCH_SIZE = 20;   // 每批并发数（LWP 走同一个 WS，不能太快）
12	const MSG_COUNT = 50;    // 每次拉取条数
13	const MAX_PAGES = 20;    // 单个会话最大翻页数
14	const BATCH_DELAY = 500;  // 批次间延迟 ms
15	
16	// ========== 工具函数 ==========
17	
18	function ts() { return new Date().toISOString().replace(/[:.]/g, '-'); }
19	
20	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
21	
22	// ========== 主流程 ==========
23	
24	(async () => {
25	  log('连接 CDP...');
26	  const browser = await chromium.connectOverCDP('http://localhost:9222');
27	  const pages = browser.contexts()[0].pages();
28	  const page = pages[0];
29	  const client = await page.context().newCDPSession(page);
30	
31	  // 找到 onetalk iframe
32	  const targets = await client.send('Target.getTargets');
33	  const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
34	  if (!ot) { log('错误: 未找到 onetalk iframe，TM 页面是否已打开？'); process.exit(1); }
35	  log('onetalk iframe 已找到');
36	
37	  const { sessionId } = await client.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
38	
39	  // 响应收集
40	  let evalResults = {};
41	  let consoleMsgs = [];
42	
43	  client.on('Target.receivedMessageFromTarget', (msg) => {
44	    if (msg.sessionId !== sessionId) return;
45	    try {
46	      const m = JSON.parse(msg.message);
47	      if (m.id && m.result) {
48	        const val = m.result.result ? m.result.result.value : null;
49	        if (val !== null && val !== undefined) {
50	          try { evalResults[m.id] = JSON.parse(val); } catch (e) { evalResults[m.id] = val; }
51	        } else {
52	          evalResults[m.id] = m.result;
53	        }
54	      }
55	      if (m.method === 'Runtime.consoleAPICalled') {
56	        const text = (m.params.args || []).map(a => a.value || a.description || '').join(' ');
57	        if (text.startsWith('[LWP')) consoleMsgs.push(text);
58	      }
59	    } catch (e) {}
60	  });
61	
62	  await client.send('Target.sendMessageToTarget', {
63	    sessionId,
64	    message: JSON.stringify({ id: 0, method: 'Runtime.enable', params: {} })
65	  });
66	
67	  // ========== Step 1: 检查并确保 SDK 已连接 ==========
68	  log('检查 SDK 状态...');
69	  await evaluate(sessionId, client, 1, `
70	    (function(){var a=window._imBaaSSDK.getAuthService();return JSON.stringify({isLogin:a.isLogin(),status:a.connectionStatus,uid:a.getLoginUid()})})()
71	  `);
72	  await sleep(2000);
73	  const sdkState = evalResults[1];
74	  log(`SDK: isLogin=${sdkState.isLogin}, status=${sdkState.status}, uid=${sdkState.uid}`);
75	
76	  if (!sdkState.isLogin || sdkState.status < 4) {
77	    log('SDK 未连接，尝试 reConnect...');
78	    await evaluate(sessionId, client, 2, `
79	      (async function(){var a=window._imBaaSSDK.getAuthService();try{await a.reConnect();await new Promise(r=>setTimeout(r,3000));return JSON.stringify({isLogin:a.isLogin(),status:a.connectionStatus})}catch(e){return JSON.stringify({error:e.message})}})()
80	    `, true);
81	    await sleep(8000);
82	    log('reConnect 结果: ' + JSON.stringify(evalResults[2]));
83	  }
84	
85	  // ========== Step 2: 劫持 WebSocket 并安装 LWP 收发器 ==========
86	  // 策略：
87	  //   1. 保存原始 send / addEventListener
88	  //   2. 劫持 send → 捕获 WS 实例
89	  //   3. 捕获后，用原始 addEventListener 给自己的 handler 订阅 message
90	  //   4. 收到响应按 mid 匹配 promise，事件驱动，无需轮询
91	  log('安装 LWP 收发器...');
92	  await evaluate(sessionId, client, 3, `
93	    (function() {
94	      var _send = WebSocket.prototype.send;
95	      var _ae = WebSocket.prototype.addEventListener;
96	      var _rem = WebSocket.prototype.removeEventListener;
97	
98	      window.__lwpPending = {};
99	      window.__lwpSeq = 0;
100	
101	      // 劫持 send → 第一次 send 时捕获 WS 并安装响应监听
102	      WebSocket.prototype.send = function(data) {
103	        if (!window.__lwpWs && this.readyState === 1) {
104	          window.__lwpWs = this;
105	          // 用原始 addEventListener 给自己的 handler 订阅（不经过劫持）
106	          _ae.call(this, 'message', function(event) {
107	            try {
108	              var raw = typeof event.data === 'string' ? event.data : '';
109	              if (raw.indexOf('"code"') < 0) return; // 不是 LWP 响应
110	              var parsed = JSON.parse(raw);
111	              var mid = parsed.headers && parsed.headers.mid;
112	              if (mid && window.__lwpPending[mid]) {
113	                var p = window.__lwpPending[mid];
114	                delete window.__lwpPending[mid];
115	                p.resolve(parsed);
116	              }
117	            } catch(e) {}
118	          });
119	          console.log('[LWP] WS captured: ' + this.url);
120	        }
121	        return _send.call(this, data);
122	      };
123	
124	      // 发 LWP 请求，返回 Promise<response>
125	      window.__lwpRequest = function(lwpPath, body) {
126	        return new Promise(function(resolve, reject) {
127	          var ws = window.__lwpWs;
128	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
129	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
130	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
131	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
132	          ws.send(req);
133	          setTimeout(function() {
134	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
135	          }, 30000);
136	        });
137	      };
138	
139	      return JSON.stringify({ installed: true });
140	    })()
141	  `);
142	  await sleep(2000);
143	  log('收发器已安装');
144	
145	  // ========== Step 3: 确认 WS 已捕获 ==========
146	  await evaluate(sessionId, client, 4, `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`);
147	  await sleep(2000);
148	  if (!evalResults[4] || !evalResults[4].ws) {
149	    log('WS 未捕获，等待心跳触发 send...');
150	    await sleep(15000);
151	    await evaluate(sessionId, client, 5, `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`);
152	    await sleep(2000);
153	    log('WS 状态: ' + JSON.stringify(evalResults[5]));
154	  } else {
155	    log('WS 已捕获: ' + evalResults[4].url);
156	  }
157	
158	  // ========== Step 4: 读取会话列表 ==========
159	  log('读取会话列表...');
160	  await evaluate(sessionId, client, 6, `
161	    (function(){
162	      var convs = window.__conversationListFullData__;
163	      if (!convs) return JSON.stringify({error:'no convs'});
164	      var list = convs.map(function(c){
165	        return { cid: c.cid, name: c.name, hasMsg: !!(c.latestMessage && c.latestMessage.content) };
166	      });
167	      return JSON.stringify({ total: list.length, convs: list });
168	    })()
169	  `);
170	  await sleep(3000);
171	  const convData = evalResults[6];
172	  log(`会话总数: ${convData.total}`);
173	  const allConvs = convData.convs;
174	
175	  // 创建输出目录
176	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
177	
178	  // 检查已抓取的会话（断点续传）
179	  const fetched = new Set();
180	  if (fs.existsSync(DATA_DIR)) {
181	    fs.readdirSync(DATA_DIR).forEach(f => {
182	      if (f.endsWith('.json')) fetched.add(f.replace('.json', ''));
183	    });
184	  }
185	  const toFetch = allConvs.filter(c => !fetched.has(sanitizeFilename(c.cid)));
186	  log(`待抓取: ${toFetch.length} / 已完成: ${fetched.size}`);
187	
188	  // ========== Step 5: 批量抓取 ==========
189	  let totalMsgs = 0;
190	  let errors = 0;
191	
192	  // 先做一个快速测试，验证 LWP 能正常工作
193	  if (toFetch.length > 0) {
194	    log('测试 LWP 请求...');
195	    const testCid = toFetch[0].cid;
196	    await evaluate(sessionId, client, 7, `
197	      (async function() {
198	        try {
199	          var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${testCid}', false, 9007199254740991, ${MSG_COUNT}, false]);
200	          return JSON.stringify({ ok: true, code: result.code, msgCount: result.body ? result.body.userMessageModels ? result.body.userMessageModels.length : 0 : 0 });
201	        } catch(e) {
202	          return JSON.stringify({ ok: false, error: e.message });
203	        }
204	      })()
205	    `, true);
206	    await sleep(5000);
207	    log('LWP 测试结果: ' + JSON.stringify(evalResults[7]));
208	  }
209	
210	  for (let i = 0; i < toFetch.length; i += BATCH_SIZE) {
211	    const batch = toFetch.slice(i, i + BATCH_SIZE);
212	    log(`批次 ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(toFetch.length / BATCH_SIZE)} (${i + 1}-${Math.min(i + BATCH_SIZE, toFetch.length)})`);
213	
214	    for (const conv of batch) {
215	      try {
216	        const cid = conv.cid;
217	        const safeName = sanitizeFilename(cid);
218	
219	        const allMessages = [];
220	        let cursor = 9007199254740991;
221	        let pageNum = 0;
222	
223	        while (pageNum < MAX_PAGES) {
224	          const msgId = 100 + (i + pageNum);
225	          evalResults[msgId] = undefined;
226	
227	          await evaluate(sessionId, client, msgId, `
228	            (async function() {
229	              try {
230	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${cid}', false, ${cursor}, ${MSG_COUNT}, false]);
231	                return JSON.stringify(result);
232	              } catch(e) {
233	                return JSON.stringify({ __error: e.message });
234	              }
235	            })()
236	          `, true);
237	          await sleep(2000);
238	
239	          const raw = evalResults[msgId];
240	          if (!raw || raw.__error) {
241	            if (raw && raw.__error === 'timeout') { log(`  [${conv.name}] 超时，跳过`); }
242	            break;
243	          }
244	
245	          let response;
246	          try {
247	            response = typeof raw === 'string' ? JSON.parse(raw) : raw;
248	          } catch (e) { log(`  [${conv.name}] 响应解析失败`); break; }
249	
250	          if (response.code !== 200) break;
251	
252	          const body = response.body;
253	          if (!body || !body.userMessageModels || body.userMessageModels.length === 0) break;
254	
255	          const msgs = body.userMessageModels;
256	          allMessages.push(...msgs);
257	
258	          if (msgs.length < MSG_COUNT || !body.nextCursor) break;
259	          cursor = body.nextCursor;
260	          pageNum++;
261	        }
262	
263	        const output = {
264	          cid: cid,
265	          name: conv.name,
266	          fetchedAt: new Date().toISOString(),
267	          totalMessages: allMessages.length,
268	          messages: allMessages
269	        };
270	
271	        fs.writeFileSync(path.join(DATA_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
272	        totalMsgs += allMessages.length;
273	        if (allMessages.length > 0) {
274	          log(`  [${conv.name}] ${allMessages.length} 条`);
275	        }
276	
277	      } catch (e) {
278	        errors++;
279	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
280	      }
281	    }
282	
283	    log(`  批次完成，累计 ${totalMsgs} 条消息，${errors} 个错误`);
284	    if (i + BATCH_SIZE < toFetch.length) await sleep(BATCH_DELAY);
285	  }
286	
287	  // ========== Step 6: 汇总报告 ==========
288	  log('');
289	  log('========== 抓取完成 ==========');
290	  log(`总会话: ${allConvs.length}`);
291	  log(`本次抓取: ${toFetch.length}`);
292	  log(`总消息数: ${totalMsgs}`);
293	  log(`错误数: ${errors}`);
294	  log(`输出目录: ${DATA_DIR}`);
295	
296	  // 生成汇总
297	  const summary = {
298	    exportedAt: new Date().toISOString(),
299	    totalConversations: allConvs.length,
300	    fetchedConversations: toFetch.length,
301	    totalMessages: totalMsgs,
302	    errors: errors,
303	    dataDir: DATA_DIR
304	  };
305	  fs.writeFileSync(
306	    path.join(DATA_DIR, '_summary.json'),
307	    JSON.stringify(summary, null, 2)
308	  );
309	
310	  process.exit(0);
311	})().catch(e => { log('致命错误: ' + e.message); process.exit(1); });
312	
313	// ========== Helper ==========
314	
315	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
316	
317	async function evaluate(sessionId, client, id, expression, awaitPromise) {
318	  await client.send('Target.sendMessageToTarget', {
319	    sessionId,
320	    message: JSON.stringify({
321	      id,
322	      method: 'Runtime.evaluate',
323	      params: { expression, awaitPromise: !!awaitPromise }
324	    })
325	  });
326	}
327	
328	function sanitizeFilename(cid) {
329	  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
330	}
